COMMENT ON COLUMN communication_policies.quiet_hours_end IS 'Recipient-local quiet-hours end.';
COMMENT ON COLUMN communication_policies.max_message_length IS 'Maximum message length for one unit.';
COMMENT ON COLUMN communication_policies.max_segments IS 'Maximum number of channel segments.';
COMMENT ON COLUMN communication_policies.retention_days IS 'Retention period for rendered messages and delivery records.';
COMMENT ON COLUMN communication_policies.approval_role IS 'Role approving the channel policy.';
COMMENT ON COLUMN communication_policies.required_content IS 'Content that every message must include.';
COMMENT ON COLUMN communication_policies.authority_statement IS 'Which artifact is authoritative.';
COMMENT ON COLUMN communication_policies.status IS 'Draft, Active, Suspended, or Retired.';
COMMENT ON COLUMN communication_policies.quiet_hours_start_hour IS 'The hour (0-23) at which the quiet window opens. Stored rather than parsed from QuietHoursStart: VALUE(LEFT(...)) does not translate — the transpiler casts the "20:00" string to a timestamp and the view errors. The sending system already knows this number, so modeling it as a parse would dress a broken derivation up as a rule.';
COMMENT ON COLUMN communication_policies.quiet_hours_end_hour IS 'Numeric hour 0-23 at which quiet hours end. Seeded 8 for comm-sms-policy, 0 for comm-email-policy.';
COMMENT ON COLUMN communication_policies.semantic_type_iri IS 'ODRL Policy class IRI.';

