-- ----------------------------------------------------------------------------
-- WitnessLoops: One row per role-question expansion loop. Each loop poses questions that only became askable because of the previous loop's predicates.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS witness_loops (
  witness_loop_id                     TEXT                 PRIMARY KEY          -- Stored logical identifier for one WitnessLoops row.
);
ALTER TABLE witness_loops ADD COLUMN IF NOT EXISTS loop_number NUMERIC;                             -- Ordinal of this expansion loop. Loop 1 is the founding set of role questions.
ALTER TABLE witness_loops ADD COLUMN IF NOT EXISTS title TEXT;                                      -- Short title for what this loop set out to make askable.
ALTER TABLE witness_loops ADD COLUMN IF NOT EXISTS premise TEXT;                                    -- Why this loop's questions became askable. For loop N>1 this names the loop N-1 predicates that made them possible.
ALTER TABLE witness_loops ADD COLUMN IF NOT EXISTS started_at TIMESTAMPTZ;                          -- Time this loop began.
ALTER TABLE witness_loops ADD COLUMN IF NOT EXISTS completed_at TIMESTAMPTZ;                        -- Time this loop was committed. Null while in progress.
ALTER TABLE witness_loops ADD COLUMN IF NOT EXISTS semantic_type_iri TEXT;                          -- Extension class IRI.
COMMENT ON TABLE witness_loops IS 'One row per role-question expansion loop. Each loop poses questions that only became askable because of the previous loop''s predicates.';
COMMENT ON COLUMN witness_loops.witness_loop_id IS 'Stored logical identifier for one WitnessLoops row.';
COMMENT ON COLUMN witness_loops.loop_number IS 'Ordinal of this expansion loop. Loop 1 is the founding set of role questions.';
COMMENT ON COLUMN witness_loops.title IS 'Short title for what this loop set out to make askable.';
COMMENT ON COLUMN witness_loops.premise IS 'Why this loop''s questions became askable. For loop N>1 this names the loop N-1 predicates that made them possible.';
COMMENT ON COLUMN witness_loops.started_at IS 'Time this loop began.';
COMMENT ON COLUMN witness_loops.completed_at IS 'Time this loop was committed. Null while in progress.';
COMMENT ON COLUMN witness_loops.semantic_type_iri IS 'Extension class IRI.';

-- ----------------------------------------------------------------------------
-- RoleQuestions: One row per question a named role wants answered. Every invented predicate in this rulebook traces back to one of these.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS role_questions (
