);
ALTER TABLE role_questions ADD COLUMN IF NOT EXISTS asking_role TEXT;                               -- The role that wants this question answered.
ALTER TABLE role_questions ADD COLUMN IF NOT EXISTS witness_loop TEXT;                              -- The expansion loop in which this question was posed.
ALTER TABLE role_questions ADD COLUMN IF NOT EXISTS question_text TEXT;                             -- The question in the role's own words.
ALTER TABLE role_questions ADD COLUMN IF NOT EXISTS why_it_matters TEXT;                            -- What goes wrong in the real world when this question cannot be answered.
ALTER TABLE role_questions ADD COLUMN IF NOT EXISTS answerable_before BOOLEAN;                      -- TRUE if the model could already answer this before its loop ran. FALSE means the loop had to invent predicates for it.
ALTER TABLE role_questions ADD COLUMN IF NOT EXISTS semantic_type_iri TEXT;                         -- Extension class IRI.
COMMENT ON TABLE role_questions IS 'One row per question a named role wants answered. Every invented predicate in this rulebook traces back to one of these.';
COMMENT ON COLUMN role_questions.role_question_id IS 'Stored logical identifier for one RoleQuestions row.';
COMMENT ON COLUMN role_questions.asking_role IS 'The role that wants this question answered.';
COMMENT ON COLUMN role_questions.witness_loop IS 'The expansion loop in which this question was posed.';
COMMENT ON COLUMN role_questions.question_text IS 'The question in the role''s own words.';
COMMENT ON COLUMN role_questions.why_it_matters IS 'What goes wrong in the real world when this question cannot be answered.';
COMMENT ON COLUMN role_questions.answerable_before IS 'TRUE if the model could already answer this before its loop ran. FALSE means the loop had to invent predicates for it.';
COMMENT ON COLUMN role_questions.semantic_type_iri IS 'Extension class IRI.';

