ALTER TABLE message_deliveries ADD COLUMN IF NOT EXISTS recipient TEXT;                             -- Who the message was sent to.
ALTER TABLE message_deliveries ADD COLUMN IF NOT EXISTS message_template TEXT;                      -- Template that was rendered for this send.
ALTER TABLE message_deliveries ADD COLUMN IF NOT EXISTS sent_by_agent TEXT;                         -- Agent that performed the send.
ALTER TABLE message_deliveries ADD COLUMN IF NOT EXISTS rendered_body TEXT;                         -- The exact body text that was transmitted, after variable substitution.
ALTER TABLE message_deliveries ADD COLUMN IF NOT EXISTS sent_at TIMESTAMPTZ;                        -- Transmission timestamp.
ALTER TABLE message_deliveries ADD COLUMN IF NOT EXISTS sent_at_local_hour INTEGER;                 -- Hour of day 0-23 in the RECIPIENT's local timezone at transmission. Stored raw because recipient-local time is what the quiet-hours rule is written against and it is not derivable from SentAt alone.
ALTER TABLE message_deliveries ADD COLUMN IF NOT EXISTS delivery_status TEXT;                       -- Sent, Delivered, Failed, Suppressed, or Bounced.
ALTER TABLE message_deliveries ADD COLUMN IF NOT EXISTS suppression_reason TEXT;                    -- When DeliveryStatus is Suppressed, why; empty string otherwise.
ALTER TABLE message_deliveries ADD COLUMN IF NOT EXISTS invoked_exception TEXT;                     -- Documented exception invoked for this delivery, when one was.
ALTER TABLE message_deliveries ADD COLUMN IF NOT EXISTS acknowledged_at TIMESTAMPTZ;                -- When the recipient acknowledged; null when not acknowledged.
ALTER TABLE message_deliveries ADD COLUMN IF NOT EXISTS semantic_type_iri TEXT;                     -- Extension IRI; per-recipient delivery events are not a PKO 2.0.0 native class.
COMMENT ON TABLE message_deliveries IS 'MessageDeliveries (added by witness loop 1).';
COMMENT ON COLUMN message_deliveries.message_delivery_id IS 'Stored logical identifier for one MessageDeliveries row.';
COMMENT ON COLUMN message_deliveries.procedure_execution IS 'The procedure execution this send was performed under.';
COMMENT ON COLUMN message_deliveries.step_execution IS 'The step execution that performed the send.';
COMMENT ON COLUMN message_deliveries.recipient IS 'Who the message was sent to.';
COMMENT ON COLUMN message_deliveries.message_template IS 'Template that was rendered for this send.';
COMMENT ON COLUMN message_deliveries.sent_by_agent IS 'Agent that performed the send.';
COMMENT ON COLUMN message_deliveries.rendered_body IS 'The exact body text that was transmitted, after variable substitution.';
COMMENT ON COLUMN message_deliveries.sent_at IS 'Transmission timestamp.';
COMMENT ON COLUMN message_deliveries.sent_at_local_hour IS 'Hour of day 0-23 in the RECIPIENT''s local timezone at transmission. Stored raw because recipient-local time is what the quiet-hours rule is written against and it is not derivable from SentAt alone.';
COMMENT ON COLUMN message_deliveries.delivery_status IS 'Sent, Delivered, Failed, Suppressed, or Bounced.';
COMMENT ON COLUMN message_deliveries.suppression_reason IS 'When DeliveryStatus is Suppressed, why; empty string otherwise.';
COMMENT ON COLUMN message_deliveries.invoked_exception IS 'Documented exception invoked for this delivery, when one was.';
COMMENT ON COLUMN message_deliveries.acknowledged_at IS 'When the recipient acknowledged; null when not acknowledged.';
COMMENT ON COLUMN message_deliveries.semantic_type_iri IS 'Extension IRI; per-recipient delivery events are not a PKO 2.0.0 native class.';

